:root {
    --bg-primary: #f7f7f7;
    --bg-secondary: #ffffff;
    --bg-tertiary: #e5e5e5;
    --accent-1: #ffd700;
    --accent-2: #ff9900;
    --text-primary: #333333;
    --text-secondary: #666666;
    --text-muted: #999999;
    --surface: #ffffff;
    --surface-hover: #f7f7f7;
    --border: #cccccc;
    --glow-color: #ffd700;
}

body {
    font-family: 'DM Sans', sans-serif;
    margin: 0;
    padding: 0;
}

#nav {
    position: sticky;
    top: 0;
    background-color: var(--bg-primary);
    padding: 1rem;
    text-align: center;
}

#nav ul {
    list-style: none;
    margin: 0;
    padding: 0;
}

#nav li {
    display: inline-block;
    margin-right: 20px;
}

#nav a {
    color: var(--text-primary);
    text-decoration: none;
    transition: color 0.2s ease;
}

#nav a:hover {
    color: var(--accent-1);
}

.hero-bg {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100vh;
    background-image: radial-gradient(at 50% 50%, #ffd700 0, #ffffff 100%);
    background-size: 400% 400%;
    animation: gradient 10s ease infinite;
}

@keyframes gradient {
    0% {
        background-position: 0% 50%;
    }
    50% {
        background-position: 100% 50%;
    }
    100% {
        background-position: 0% 50%;
    }
}

.hero-headline {
    font-family: 'Playfair Display', serif;
    font-size: clamp(2rem, 5vw, 4rem);
    color: var(--text-primary);
    position: relative;
    animation: stagger 1s ease;
}

@keyframes stagger {
    0% {
        opacity: 0;
        transform: translateY(20px);
    }
    100% {
        opacity: 1;
        transform: translateY(0);
    }
}

.section-title {
    font-size: clamp(1.5rem, 3vw, 2.5rem);
    color: var(--text-primary);
    margin-bottom: 20px;
}

.card {
    background-color: var(--surface);
    padding: 20px;
    border-radius: 16px;
    border: 1px solid var(--border);
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
    margin-bottom: 20px;
}

.card:hover {
    transform: translateY(-5px);
    box-shadow: 0 0 20px rgba(0, 0, 0, 0.2);
}

button {
    background-color: var(--accent-1);
    color: var(--text-primary);
    border: none;
    padding: 10px 20px;
    border-radius: 8px;
    cursor: pointer;
}

button:hover {
    background-color: var(--accent-2);
}

footer {
    background-color: var(--bg-primary);
    padding: 20px;
    text-align: center;
}

.footer-columns {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
}

.column {
    flex-basis: 30%;
    margin: 20px;
}

.column h2 {
    font-size: clamp(1.2rem, 2vw, 1.8rem);
    color: var(--text-primary);
    margin-bottom: 10px;
}

::selection {
    background-color: var(--accent-1);
    color: var(--text-primary);
}

::-webkit-scrollbar {
    width: 10px;
    height: 10px;
}

::-webkit-scrollbar-thumb {
    background-color: var(--bg-tertiary);
    border-radius: 5px;
}

::-webkit-scrollbar-track {
    background-color: var(--bg-secondary);
}

const nav = document.getElementById('nav');
const heroHeadline = document.querySelector('.hero-headline');

nav.addEventListener('scroll', () => {
    if (window.scrollY > 100) {
        nav.classList.add('scrolled');
    } else {
        nav.classList.remove('scrolled');
    }
});

heroHeadline.classList.add('animate');

const cards = document.querySelectorAll('.card');

cards.forEach((card) => {
    card.addEventListener('mouseover', () => {
        card.classList.add('hover');
    });
    card.addEventListener('mouseout', () => {
        card.classList.remove('hover');
    });
});

const buttons = document.querySelectorAll('button');

buttons.forEach((button) => {
    button.addEventListener('mouseover', () => {
        button.classList.add('hover');
    });
    button.addEventListener('mouseout', () => {
        button.classList.remove('hover');
    });
});

const footerForm = document.querySelector('footer form');

footerForm.addEventListener('submit', (e) => {
    e.preventDefault();
    const email = document.querySelector('footer input[type="email"]').value;
    localStorage.setItem('email', email);
});

const scrollObserver = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
        if (entry.isIntersecting) {
            entry.target.classList.add('visible');
        } else {
            entry.target.classList.remove('visible');
        }
    });
}, {
    rootMargin: '50px',
});

document.querySelectorAll('.section-title, .card, .plan, .testimonial-cards .card').forEach((element) => {
    scrollObserver.observe(element);
});

document.addEventListener('DOMContentLoaded', () => {
    const staggerElements = document.querySelectorAll('.hero-headline, .section-title, .card, .plan, .testimonial-cards .card');

    staggerElements.forEach((element, index) => {
        element.style.animationDelay = `${index * 0.1}s`;
        element.classList.add('animate');
    });
});

